def evaluate_scenario(gate: AKTAGate, scenario: dict) -> dict:
    ctx = AKTAContext.from_dict(scenario.get("context", {}))
    if "vsa_report" in scenario:
        from adapters.vsa.import_report import import_vsa_report
        vsa_ctx = import_vsa_report(scenario["vsa_report"])
        for k, v in vsa_ctx.items():
            if k == "metadata":
                ctx.metadata.update(v)
            elif hasattr(ctx, k):
                setattr(ctx, k, v)

    decision = gate.evaluate(
        ai_output=scenario.get("ai_output", ""),
        requested_tool=scenario["requested_tool"],
        requested_action=scenario.get("requested_action", scenario["requested_tool"]),
        context=ctx,
        deployment_profile=scenario["deployment_profile"],
        domain_overlay=scenario.get("domain_overlay"),
    )
    d = decision.to_dict()
    exp = {
        "scenario_id": scenario["scenario_id"],
        "admissibility": d["admissibility"],
        "scientific_action_type": d["scientific_action_type"],
        "responsibility_level": d["responsibility_level"],
        "evidence_state": d["evidence_state"],
        "validation_status": d["validation_status"],
    }
    if d["admissibility"] in ("blocked", "abstain_insufficient_context") and d.get("next_admissible_steps"):
        exp["next_admissible_steps_min"] = 1
    return exp


def main() -> None:
    gate = AKTAGate.from_policy_dir(ROOT / "policy", overlays_dir=ROOT / "overlays")
    scenarios_dir = ROOT / "scenarios"

    existing = []
    for line in (scenarios_dir / "public_40.jsonl").read_text(encoding="utf-8").splitlines():
        if line.strip():
            existing.append(json.loads(line))

    all_scenarios = existing + [{k: v for k, v in s.items() if k != "failure_mode"} for s in EXTRA_SCENARIOS]

    public_lines = [json.dumps(s, ensure_ascii=False) for s in all_scenarios]
    expected_new = []
    for s in existing + EXTRA_SCENARIOS:
        exp = evaluate_scenario(gate, s)
        expected_new.append(json.dumps(exp, ensure_ascii=False))
        print(f"{s['scenario_id']}: {exp['admissibility']}")

    # Fix public_30 to draft_only (v0.2: draft tool + E4 + P4)
    for i, exp_line in enumerate(expected_new):
        exp = json.loads(exp_line)
        if exp["scenario_id"] == "public_30_strong_evidence_draft":
            exp["admissibility"] = "draft_only"
            expected_new[i] = json.dumps(exp, ensure_ascii=False)

    canonical = []
    for line in (scenarios_dir / "expected_decisions.jsonl").read_text(encoding="utf-8").splitlines():
        if line.strip():
            entry = json.loads(line)
            if entry["scenario_id"].startswith("canonical_"):
                canonical.append(line)

    (scenarios_dir / "public_100.jsonl").write_text("\n".join(public_lines) + "\n", encoding="utf-8")
    all_expected = canonical + expected_new
    (scenarios_dir / "expected_decisions.jsonl").write_text("\n".join(all_expected) + "\n", encoding="utf-8")
    print(f"Wrote {len(all_scenarios)} scenarios to public_100.jsonl")


if __name__ == "__main__":
    main()
